import React, { Fragment, useState } from "react";

const ForgotPassword = () => {
  const [email, setEmail] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const submitHandler = async () => {
    if (!email) {
      setError("Email is required");
      setMessage("");
      return;
    }

    try {
      // For now only frontend message
      setMessage("Password reset link has been sent to your email");
      setError("");
    } catch (err) {
      console.log(err);
      setError("Something went wrong");
      setMessage("");
    }
  };

  return (
    <Fragment>
      <div className="text-center text-2xl mb-6">Forgot Password</div>

      <div className="space-y-4">
        {message && <div className="text-green-500 text-sm">{message}</div>}
        {error && <div className="text-red-500 text-sm">{error}</div>}

        <div className="flex flex-col">
          <label htmlFor="email">
            Email address<span className="text-sm text-gray-600 ml-1">*</span>
          </label>
          <input
            type="email"
            id="email"
            value={email}
            onChange={(e) => {
              setEmail(e.target.value);
              setError("");
              setMessage("");
            }}
            className="px-4 py-2 focus:outline-none border"
          />
        </div>

        <div
          onClick={submitHandler}
          style={{ background: "#303031" }}
          className="px-4 py-2 text-white text-center cursor-pointer font-medium"
        >
          Send Reset Link
        </div>
      </div>
    </Fragment>
  );
};

export default ForgotPassword;
